              "type": "string",
              "description": "Use \"Observation\" for vitals observations."
            },
            "category": {
              "type": "array",
              "items": {
                "type": "object",
                "properties": {
                  "coding": {
                    "type": "array",
                    "items": {
                      "type": "object",
